CACHE_FILE = os.path.join(os.path.dirname(__file__), 'cache.json')
PROSPECTUS_DIR = os.path.join(os.path.dirname(__file__), 'prospectus')

def _find_pdf(preferred_path, keyword_patterns):
    if preferred_path and os.path.exists(preferred_path):
        return preferred_path
    try:
        if not os.path.isdir(PROSPECTUS_DIR):
            return None
        files = [f for f in os.listdir(PROSPECTUS_DIR) if f.lower().endswith('.pdf')]
        for f in files:
            name = f.lower()
            if all(k in name for k in keyword_patterns):
                return os.path.join(PROSPECTUS_DIR, f)
        return os.path.join(PROSPECTUS_DIR, files[0]) if files else None
    except Exception:
        return None

_preferred_prospectus = os.path.join(PROSPECTUS_DIR, 'A1-MRE_Fund_Prospectus.pdf')
_preferred_system_overview = os.path.join(PROSPECTUS_DIR, 'A1-MRE_System_Overview.pdf')
PROSPECTUS_FILE = _find_pdf(_preferred_prospectus, ['prospectus'])
SYSTEM_OVERVIEW_FILE = _find_pdf(_preferred_system_overview, ['system', 'overview'])


