js = """
    <script>
    // Helper to format a Date object to YYYY-MM-DD in America/New_York timezone
    const fmtDateInTZ = (dateObj) => {
      try {
        return new Intl.DateTimeFormat('en-CA', { timeZone: 'America/New_York' }).format(dateObj);
      } catch (e) {
        return dateObj.toISOString().slice(0,10);
      }
    };

    async function updateTimestamp() {
      try {
        const resp = await fetch('/cache.json', {cache: 'no-store'});
        if (!resp.ok) return;
        const j = await resp.json();
        const last = j.last_updated_utc;
        if (!last) return;
        const d = new Date(last);
        // format in America/New_York if available
        let opts = { year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit', hour12: true };
        let s;
        try {
          s = d.toLocaleString('en-US', Object.assign({timeZone: 'America/New_York'}, opts));
        } catch(e) {
          s = d.toLocaleString('en-US', opts) + ' UTC';
        }
        const el = document.getElementById('last_updated');
        if (el) el.innerText = s + ' ET';

        // persistent keys
        const countsKey = 'top10_update_counts';
        const lastSeenKey = 'top10_last_seen_ts';

        // existing stored values
        let counts = {};
        try { counts = JSON.parse(localStorage.getItem(countsKey) || '{}'); } catch(e) { counts = {}; }
        const prevTs = localStorage.getItem(lastSeenKey);

        // If no prevTs, initialize without incrementing (treat current as baseline)
        if (!prevTs) {
          localStorage.setItem(lastSeenKey, last);
        } else {
          if (new Date(last) > new Date(prevTs)) {
            // there is a newer timestamp -> increment counter for that date (in NY tz)
            const dateKey = fmtDateInTZ(d);
            counts[dateKey] = (counts[dateKey] || 0) + 1;
            localStorage.setItem(countsKey, JSON.stringify(counts));
            localStorage.setItem(lastSeenKey, last);
          }
        }

        // compute today/yesterday in NY tz
        const now = new Date();
        const todayKey = fmtDateInTZ(now);
        const yesterdayKey = fmtDateInTZ(new Date(now.getTime() - 24*3600*1000));
        const todayCount = counts[todayKey] || 0;
        const yesterdayCount = counts[yesterdayKey] || 0;

        const countsEl = document.getElementById('update_counts');
        if (countsEl) countsEl.innerText = `Today: ${todayCount}  Yesterday: ${yesterdayCount}`;

        // indicator: show new day data if today's count > 0
        const indicatorEl = document.getElementById('last_updated_indicator');
        if (indicatorEl) {
          if (todayCount > 0) indicatorEl.innerHTML = `<span style='color:#0f9d58;font-weight:700;'>New day data (${todayCount})</span>`;
          else indicatorEl.innerHTML = '';
        }

      } catch (e) { console.debug('timestamp update failed', e); }
    }

    // Mark as seen clears today's count and resets lastSeen timestamp
    document.addEventListener('click', function(e) {
      if (e.target && e.target.id === 'mark_seen') {
        const countsKey = 'top10_update_counts';
        const lastSeenKey = 'top10_last_seen_ts';
        let counts = {};
        try { counts = JSON.parse(localStorage.getItem(countsKey) || '{}'); } catch(e) { counts = {}; }
        const now = new Date();
        const todayKey = fmtDateInTZ(now);
        counts[todayKey] = 0;
        localStorage.setItem(countsKey, JSON.stringify(counts));
        // bump last seen to now to avoid immediate increments for existing timestamp
        localStorage.setItem(lastSeenKey, new Date().toISOString());
        // update UI immediately
        const countsEl = document.getElementById('update_counts');
        const indicatorEl = document.getElementById('last_updated_indicator');
        if (countsEl) countsEl.innerText = `Today: 0  Yesterday: ${counts[fmtDateInTZ(new Date(now.getTime() - 24*3600*1000))] || 0}`;
        if (indicatorEl) indicatorEl.innerHTML = '';
      }
    });

    // initial update and periodic polling every 30s
    updateTimestamp();
    setInterval(updateTimestamp, 30000);
    </script>
    """
