def _df_to_excel_bytes(df, sheet_name='Sheet1'):
    bio = io.BytesIO()
    engine = None
    try:
        import xlsxwriter  # noqa: F401
        engine = 'xlsxwriter'
    except Exception:
        engine = None
    if engine is None:
        try:
            import openpyxl  # noqa: F401
            engine = 'openpyxl'
        except Exception:
            engine = None
    if engine is None:
        return None
    with pd.ExcelWriter(bio, engine=engine) as writer:
        df.to_excel(writer, index=False, sheet_name=sheet_name[:31])
    return bio.getvalue()

