def _activity_proxy(rel_vol, vol_z, dollar_vol):
    try:
        rv = None if rel_vol is None else float(rel_vol)
    except Exception:
        rv = None
    try:
        vz = None if vol_z is None else float(vol_z)
    except Exception:
        vz = None
    try:
        dv = None if dollar_vol is None else float(dollar_vol)
    except Exception:
        dv = None

    score = 0
    if rv is not None:
        if rv >= 3:
            score += 2
        elif rv >= 2:
            score += 1
    if vz is not None:
        if vz >= 3:
            score += 2
        elif vz >= 2:
            score += 1
    if dv is not None:
        if dv >= 500_000_000:
            score += 2
        elif dv >= 100_000_000:
            score += 1

    if score >= 4:
        signal = 'High'
    elif score >= 2:
        signal = 'Med'
    elif score >= 1:
        signal = 'Low'
    else:
        signal = 'Normal'

    bits = []
    if rv is not None:
        bits.append(f"RelVol {rv:.2f}x")
    if vz is not None:
        bits.append(f"Z {vz:.2f}")
    if dv is not None:
        bits.append(f"$Vol {dv/1_000_000:.0f}M")
    note = ', '.join(bits) if bits else 'N/A'
    return signal, note

