def signal_icon(pct):
    if pct is None:
        return '⚪️'
    try:
        p = float(pct)
    except Exception:
        return '⚪️'
    if p >= 100:
        return '🟩🟩'
    if p >= 50:
        return '🟩'
    if p >= 20:
        return '🟢'
    if p >= 5:
        return '🟨'
    if p > 0:
        return '🟨'
    return '🔴'

def _norm_cdf(x):
    try:
        return 0.5 * (1.0 + math.erf(x / math.sqrt(2.0)))
    except Exception:
        return None

def _prob_price_geq(s0, target, mu, sigma, days):
    if s0 is None or target is None or mu is None or sigma is None:
        return None
    try:
        s0 = float(s0)
        target = float(target)
        if s0 <= 0 or target <= 0:
            return None
        mu_d = float(mu) * float(days)
        sd_d = float(sigma) * (float(days) ** 0.5)
        if sd_d <= 0:
            return 1.0 if target <= s0 * math.exp(mu_d) else 0.0
        z = (math.log(target / s0) - mu_d) / sd_d
        cdf = _norm_cdf(z)
        return None if cdf is None else float(1.0 - cdf)
    except Exception:
        return None

def _fmt_pct(p):
    return 'N/A' if p is None else f"{float(p) * 100:.2f}%"

def _fmt_price(x):
    return 'N/A' if x is None else f"${float(x):.2f}"

