def _group_to_pdf_bytes(group_name, df):
    # Try to create a simple PDF table using reportlab if available
    try:
        from reportlab.lib.pagesizes import letter
        from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph
        from reportlab.lib import colors
        from reportlab.lib.styles import getSampleStyleSheet
    except Exception:
        return None
    buf = io.BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=letter)
    styles = getSampleStyleSheet()
    elems = []
    elems.append(Paragraph(f'Group: {group_name}', styles['Heading2']))
    # build table data
    headers = list(df.columns)
    data = [headers]
    for _, r in df.iterrows():
        row = []
        for h in headers:
            v = r.get(h, '')
            if pd.isna(v):
                v = ''
            row.append(str(v))
        data.append(row)
    t = Table(data, repeatRows=1)
    t.setStyle(TableStyle([
        ('BACKGROUND',(0,0),(-1,0),colors.grey),
        ('TEXTCOLOR',(0,0),(-1,0),colors.whitesmoke),
        ('ALIGN',(0,0),(-1,-1),'LEFT'),
        ('GRID',(0,0),(-1,-1),0.5,colors.black),
    ]))
    elems.append(t)
    doc.build(elems)
    buf.seek(0)
    return buf.read()

def _normalize_positions_df(df):
    """Normalize uploaded positions CSVs:
    - If the first data row contains header names (e.g. 'Symbol'), promote it to columns
    - Strip column names
    - Normalize numeric/currency columns (price, market value, cost basis, cost per share, qty)
    """
    if df is None or df.empty:
        return df
    # If first row contains header-like values (e.g., 'Symbol'), promote it
    try:
        first_row = df.iloc[0].astype(str).str.lower()
        if first_row.str.contains('symbol').any() or first_row.str.contains('ticker').any():
            df.columns = df.iloc[0].astype(str).tolist()
            df = df[1:].reset_index(drop=True)
    except Exception:
        pass

    # normalize column names
    try:
        df.columns = [str(c).strip().replace('\ufeff','') for c in df.columns]
    except Exception:
        df.columns = [str(c).strip() for c in df.columns]

    # helper: find columns by keyword
    def _find(col_keywords):
        for c in df.columns:
            lc = str(c).lower()
            for k in col_keywords:
                if k in lc:
                    return c
        return None

    sym_col = _find(['symbol', 'ticker'])
    qty_col = _find(['qty', 'quantity', 'shares'])
    price_col = _find(['price', 'last price', 'last_price'])
    cost_total_col = _find(['cost basis', 'costbasis', 'cost basis', 'cost_basis', 'cost total'])
    cost_per_col = _find(['cost/', 'cost per', 'cost_per', 'cost/share', 'cost per share'])
    market_col = _find(['mkt val', 'market value', 'market_value', 'mkt_val'])

    # clean numeric-like columns: remove $ and commas, coerce
    def _clean_money(col):
        if col and col in df.columns:
            df[col] = df[col].astype(str).str.replace(r'[^0-9.\-]', '', regex=True)
            df[col] = pd.to_numeric(df[col], errors='coerce').fillna(0)

    if price_col:
        _clean_money(price_col)
    if cost_total_col:
        _clean_money(cost_total_col)
    if cost_per_col:
        _clean_money(cost_per_col)
    if market_col:
        _clean_money(market_col)

    if qty_col and qty_col in df.columns:
        # replace '--' or similar placeholders
        df[qty_col] = df[qty_col].astype(str).str.replace('--', '0').str.replace(',', '')
        df[qty_col] = pd.to_numeric(df[qty_col], errors='coerce').fillna(0)

    return df

